import { PieChart, Pie, Sector } from '@kayou/uiCharts/PieChart';
        import { ResponsiveContainer } from '@kayou/uiCharts/ResponsiveContainer';

        // Basic pie chart
        const data = [
          { name: 'Group A', value: 400 },
